changeSet.sql:
CREATE TABLE associate_models
(
	id serial,
	risk_model_id integer NOT NULL,
	name character varying (255) NOT NULL DEFAULT '',
	description text DEFAULT NULL,
	owner_id integer DEFAULT NULL,
	created_by_id integer DEFAULT NULL,
	updated_by_id integer DEFAULT NULL,
	created_at timestamp without time zone NOT NULL DEFAULT now(),
	updated_at timestamp without time zone NOT NULL DEFAULT now(),
	CONSTRAINT pk_associate_models PRIMARY KEY (id)
	, CONSTRAINT fk_associate_models_to_risk_model FOREIGN KEY (risk_model_id) REFERENCES risk_models (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_associate_models_to_owner_id FOREIGN KEY (owner_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_associate_models_to_created_by FOREIGN KEY (created_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_associate_models_to_updated_by FOREIGN KEY (updated_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_associate_models_risk_model ON associate_models (risk_model_id);
CREATE INDEX i_associate_models_risk_model_id_name ON associate_models (risk_model_id, name);
CREATE INDEX i_associate_models_name ON associate_models (name);
CREATE INDEX i_associate_models_created_at ON associate_models (created_at);
CREATE INDEX i_associate_models_owner ON associate_models (owner_id);
CREATE INDEX i_associate_models_created_by ON associate_models (created_by_id);
CREATE INDEX i_associate_models_updated_by ON associate_models (updated_by_id);
